mapper.select:
SELECT * FROM ( SELECT ROWNUM AS rn, sq.* FROM ( SELECT p.project_id AS "projectId", p.owner_id AS "ownerId", p.project_name AS "projectName", p.identifier AS "identifier", DBMS_LOB.SUBSTR(p.description, 1000, 1) AS "description", p.project_url AS "projectUrl", p.status_code AS "statusCode", c.note AS "statusName", p.start_date AS "startDate", p.end_date AS "endDate", p.created_at AS "createdAt", p.git_url AS "gitUrl", owner.user_name AS "ownerName" FROM project p LEFT JOIN users owner ON p.owner_id = owner.user_id LEFT JOIN common_code c ON p.status_code = c.code_id AND c.code_name = '0A' WHERE EXISTS ( SELECT 1 FROM project_member pm JOIN team_member tm ON pm.team_member_id = tm.team_member_id WHERE pm.project_id = p.project_id AND tm.user_id = #{ownerId} )
AND p.project_name LIKE '%' || #{searchProjectName} || '%'
AND owner.user_name LIKE '%' || #{searchOwnerName} || '%'
AND p.status_code = #{searchStatusCode}
ORDER BY p.created_at DESC, p.project_id DESC ) sq WHERE ROWNUM <= #{offset} + #{pageSize} ) WHERE rn > #{offset}

SELECT COUNT(*) FROM project_member
WHERE project_id = #{projectId} AND
team_member_id = #{teamMemberId}

